using Azure.Messaging.ServiceBus;
using Microsoft.Azure.Functions.Worker;
using Microsoft.Extensions.Logging;

public class OrderProcessor
{
    private readonly ILogger<OrderProcessor> _logger;
    private readonly ITransformService _transformer;

    public OrderProcessor(ILogger<OrderProcessor> logger, ITransformService transformer)
    {
        _logger = logger;
        _transformer = transformer;
    }

    [Function("ProcessOrder")]
    [ServiceBusOutput("processed-orders", Connection = "ServiceBusConnection")]
    public async Task<OrderResult> Run(
        [ServiceBusTrigger("raw-orders", Connection = "ServiceBusConnection")]
        ServiceBusReceivedMessage message,
        ServiceBusMessageActions messageActions,
        FunctionContext context)
    {
        var correlationId = message.CorrelationId ?? message.MessageId;
        using var scope = _logger.BeginScope(new { correlationId });

        try
        {
            var raw = message.Body.ToString();
            _logger.LogInformation("Processing order {MessageId}", message.MessageId);

            var result = await _transformer.TransformAsync(raw);

            // Explicit complete — settled by output binding delivery
            await messageActions.CompleteMessageAsync(message);

            _logger.LogInformation("Order {MessageId} processed successfully", message.MessageId);
            return result;
        }
        catch (InvalidMessageFormatException ex)
        {
            // Permanent failure — dead-letter immediately, do not retry
            _logger.LogError(ex, "Malformed message {MessageId} — dead-lettering", message.MessageId);
            await messageActions.DeadLetterMessageAsync(message,
                deadLetterReason: "InvalidFormat",
                deadLetterErrorDescription: ex.Message);
            return null; // No output binding message
        }
        // Transient exceptions propagate — runtime abandons message for retry
    }
}

using Microsoft.Azure.Functions.Worker;
using Microsoft.DurableTask;
using Microsoft.DurableTask.Client;

public class BulkOrderOrchestrator
{
    [Function(nameof(BulkOrderOrchestrator))]
    public static async Task<List<OrderResult>> RunOrchestrator(
        [OrchestrationTrigger] TaskOrchestrationContext context)
    {
        var input = context.GetInput<BulkOrderInput>();
        var logger = context.CreateReplaySafeLogger(nameof(BulkOrderOrchestrator));

        logger.LogInformation("Starting fan-out for {Count} orders", input.OrderIds.Count);

        // Fan-out: start all activities in parallel
        var tasks = input.OrderIds
            .Select(orderId => context.CallActivityAsync<OrderResult>(
                nameof(ProcessSingleOrder),
                orderId,
                new TaskOptions(new TaskRetryOptions(
                    new RetryPolicy(maxNumberOfAttempts: 3,
                        firstRetryInterval: TimeSpan.FromSeconds(5))))))
            .ToList();

        // Fan-in: wait for all
        var results = await Task.WhenAll(tasks);

        logger.LogInformation("All {Count} orders processed", results.Length);
        return results.ToList();
    }

    [Function(nameof(ProcessSingleOrder))]
    public static async Task<OrderResult> ProcessSingleOrder(
        [ActivityTrigger] string orderId,
        FunctionContext context)
    {
        // Activity can do I/O, call APIs — no determinism constraints
        var logger = context.GetLogger(nameof(ProcessSingleOrder));
        logger.LogInformation("Processing order {OrderId}", orderId);
        // ... actual processing logic
        return new OrderResult { OrderId = orderId, Status = "Completed" };
    }

    [Function("StartBulkOrchestration")]
    public static async Task<HttpResponseData> HttpStart(
        [HttpTrigger(AuthorizationLevel.Function, "post")] HttpRequestData req,
        [DurableClient] DurableTaskClient client,
        FunctionContext context)
    {
        var input = await req.ReadFromJsonAsync<BulkOrderInput>();
        var instanceId = await client.ScheduleNewOrchestrationInstanceAsync(
            nameof(BulkOrderOrchestrator), input);
        return await client.CreateCheckStatusResponseAsync(req, instanceId);
    }
}

